OSPF_路由:
!
router ospf {{ ospf_process_id }}
 router-id {{ ospf_router_id }}
 network {{ ospf_net_1 }} {{ ospf_mask_1 }} area {{ ospf_area }}
 network {{ ospf_net_2 }} {{ ospf_mask_2 }} area {{ ospf_area }}
!
interface {{ ospf_interface }}
 ip ospf network point-to-point
 ip ospf hello-interval {{ ospf_hello }}
 ip ospf dead-interval {{ ospf_dead }}
 ip ospf cost {{ ospf_cost }}
!
